export default async function emulatorNavigate({
  data = {},
  content,
  emulator,
}) {
  const { action, url } = data;

  if (action === "current-info") {
    const iframe = emulator.iframe;
    return {
      url: iframe?.src || "",
    };
  }

  if (action === "reload") {
    try {
      const iframe = emulator.iframe;
      if (!iframe) {
        return { success: false, error: "No iframe available" };
      }
      emulator.iframeLoaded = false;
      const loadPromise = listenIframeLoad(iframe);
      iframe.src = iframe.src;
      await loadPromise;
      return {
        success: true,
        url: iframe.src,
      };
    } catch (err) {
      return {
        success: false,
        error: err.message,
      };
    }
  }

  if (action === "go") {
    try {
      if (!url) {
        return { success: false, error: "No URL provided" };
      }
      emulator.iframeLoaded = false;

      let iframe = emulator.iframe;
      let loadPromise;

      if (iframe) {
        // iframe 已存在，先注册监听器再更新 URL
        loadPromise = listenIframeLoad(iframe);
        emulator.iframeUrl = url;
      } else {
        // iframe 不存在，先设置 URL 触发创建，再等待并监听
        emulator.iframeUrl = url;
        iframe = await pollIframe(emulator);
        loadPromise = listenIframeLoad(iframe);
      }

      await loadPromise;
      return {
        success: true,
        url: iframe.src,
      };
    } catch (err) {
      return {
        success: false,
        error: err.message,
      };
    }
  }
}

function listenIframeLoad(iframe, timeout = 30000) {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      cleanup();
      reject(new Error("Iframe load timeout"));
    }, timeout);
    const onLoad = () => {
      cleanup();
      resolve();
    };
    const onError = () => {
      cleanup();
      reject(new Error("Iframe load failed"));
    };
    const cleanup = () => {
      clearTimeout(timer);
      iframe.removeEventListener("load", onLoad);
      iframe.removeEventListener("error", onError);
    };
    iframe.addEventListener("load", onLoad);
    iframe.addEventListener("error", onError);
  });
}

function pollIframe(emulator, timeout = 5000) {
  return new Promise((resolve, reject) => {
    const iframe = emulator.iframe;
    if (iframe) {
      resolve(iframe);
      return;
    }
    const timer = setTimeout(() => {
      clearInterval(interval);
      reject(new Error("Iframe not available"));
    }, timeout);
    const interval = setInterval(() => {
      const iframe = emulator.iframe;
      if (iframe) {
        clearTimeout(timer);
        clearInterval(interval);
        resolve(iframe);
      }
    }, 50);
  });
}

export default async function fetchUrl({ data = {}, content }) {
  const {
    url,
    maxSize = 32 * 1024, // 32KB
    cleanHTML = true, // 如果遇到是html内容，是否清理多余标签，只返回包含文本的内容
  } = data;

  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  data = await response.text();

  // 确定是html内容，才清理多余标签
  if (cleanHTML && data.toLocaleLowerCase().includes("<!doctype html")) {
    data = clearHTML(data);
  }

  if (maxSize && data.length > maxSize) {
    data = data.slice(0, maxSize);
  }

  return data;
}

const clearHTML = (html) => {
  const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  let bodyContent = bodyMatch ? bodyMatch[1] : html;
  bodyContent = bodyContent.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "");
  bodyContent = bodyContent.replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, "");
  bodyContent = bodyContent.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "");
  bodyContent = bodyContent.replace(
    /<noscript[^>]*>[\s\S]*?<\/noscript>/gi,
    "",
  );
  bodyContent = bodyContent.replace(/<!--[\s\S]*?-->/g, "");
  bodyContent = bodyContent.replace(/<iframe[^>]*>[\s\S]*?<\/iframe>/gi, "");

  const template = document.createElement("template");
  template.innerHTML = bodyContent;
  const allowedAttrs = [
    "href",
    "src",
    "alt",
    "title",
    "role",
    "aria-label",
    "aria-labelledby",
    "aria-describedby",
    "aria-hidden",
    "aria-expanded",
    "aria-disabled",
    "aria-pressed",
    "aria-checked",
    "aria-selected",
    "for",
    "type",
    "name",
    "value",
    "placeholder",
    "disabled",
    "checked",
    "selected",
    "multiple",
    "maxlength",
    "minlength",
    "pattern",
    "required",
    "readonly",
  ];
  template.content.querySelectorAll("*").forEach((el) => {
    const attrs = [...el.attributes];
    attrs.forEach((attr) => {
      if (!allowedAttrs.includes(attr.name) && !attr.name.startsWith("aria-")) {
        el.removeAttribute(attr.name);
      }
    });
  });
  const removeEmpty = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        removeEmpty(child);
      }
    });
    if (
      el.textContent.trim() === "" &&
      !el.hasAttribute("src") &&
      !el.hasAttribute("href")
    ) {
      el.remove();
    }
  };
  removeEmpty(template.content);
  const simplifyWrappers = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        simplifyWrappers(child);
        const tagName = child.tagName.toLowerCase();
        if (
          [
            "span",
            "b",
            "i",
            "u",
            "strong",
            "em",
            "small",
            "mark",
            "sub",
            "sup",
          ].includes(tagName)
        ) {
          const textContent = child.textContent;
          const importantAttrs = ["href", "src", "alt", "title", "role"];
          const hasImportantAttr = [...child.attributes].some(
            (attr) =>
              importantAttrs.includes(attr.name) ||
              attr.name.startsWith("aria-"),
          );
          if (
            child.childNodes.length === 1 &&
            child.childNodes[0].nodeType === 3 &&
            !hasImportantAttr
          ) {
            el.replaceChild(document.createTextNode(textContent), child);
          }
        }
      }
    });
  };
  simplifyWrappers(template.content);
  const unwrapNesting = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        unwrapNesting(child);
        const importantAttrs = [
          "href",
          "src",
          "alt",
          "title",
          "role",
          "for",
          "type",
          "name",
          "value",
          "placeholder",
          "disabled",
          "checked",
          "selected",
        ];
        const hasImportantAttr = [...child.attributes].some(
          (attr) =>
            importantAttrs.includes(attr.name) || attr.name.startsWith("aria-"),
        );
        if (
          child.childNodes.length === 1 &&
          child.childNodes[0].nodeType === 1 &&
          !hasImportantAttr
        ) {
          const inner = child.childNodes[0];
          el.replaceChild(inner.cloneNode(true), child);
        }
      }
    });
  };
  unwrapNesting(template.content);
  return template.innerHTML;
};

