export default async function getSkill({ data = {}, content }) {
  const { all, name, file } = data;

  await new Promise((resolve) => setTimeout(resolve, 500));

  if (all) {
    const skillDesc = [];

    try {
      const skillDir = await get("mazmot/skills");

      if (skillDir) {
        for await (const [skillName, handle] of skillDir.entries()) {
          if (handle.kind === "dir") {
            const skillFile = await get(`mazmot/skills/${skillName}/SKILL.md`, {
              create: false,
            });

            if (skillFile) {
              const skillMd = await skillFile.text();

              if (!skillMd.trim()) {
                continue;
              }

              const frontMatterMatch = skillMd.match(/^---\n([\s\S]*?)\n---/);
              const yamlConfig = yaml.load(frontMatterMatch[1]);

              const desc = yamlConfig.description;
              delete yamlConfig.description;

              skillDesc.push({
                ...yamlConfig,
                name: skillName,
                desc,
              });
            }
          }
        }
      }
    } catch (error) {
      console.error("Error reading skills:", error);
    }

    return skillDesc;
  }

  if (name) {
    try {
      const filePath = file
        ? `mazmot/skills/${name}/${file}`
        : `mazmot/skills/${name}/SKILL.md`;

      const fileHandle = await get(filePath, { create: false });

      if (!fileHandle) {
        return {
          name: name,
          file: file || "SKILL.md",
          error: "Skill not found",
        };
      }

      const fileContent = await fileHandle.text();

      if (!fileContent.trim()) {
        return {
          name: name,
          file: file || "SKILL.md",
          error: "File is empty",
        };
      }

      return {
        name: name,
        file: file || "SKILL.md",
        content: fileContent,
      };
    } catch (error) {
      return {
        name: name,
        file: file || "SKILL.md",
        error: "Skill not found",
      };
    }
  }
}

export default async function runJS({ data = {}, content }) {
  let code = "";

  if (!code && content) {
    const temp = $(`<template>${content}</template>`);
    const scriptEl = temp.$("script[type='text/plain']");
    if (scriptEl) {
      code = scriptEl.html.trim();
    } else {
      throw new Error(
        "必须将JS代码包裹在<script type='text/plain'></script>标签中",
      );
    }
  }

  if (!code) {
    throw new Error("没有JS代码，无法执行");
  }

  const base64Code = btoa(
    encodeURIComponent(code).replace(/%([0-9A-F]{2})/g, (match, p1) =>
      String.fromCharCode(parseInt(p1, 16)),
    ),
  );

  const workerCode = `
    const code = decodeURIComponent(escape(atob('${base64Code}')));
    const fn = new Function(code);
    const result = fn();
    if (result instanceof Promise) {
      result.then(r => postMessage({ type: 'result', value: r }))
            .catch(e => postMessage({ type: 'error', message: e.message, stack: e.stack }));
    } else {
      postMessage({ type: 'result', value: result });
    }
  `;

  const blob = new Blob([workerCode], { type: "application/javascript" });
  const url = URL.createObjectURL(blob);

  return new Promise((resolve, reject) => {
    const worker = new Worker(url);
    worker.onmessage = (e) => {
      if (e.data.type === "result") {
        resolve(e.data.value);
      } else if (e.data.type === "error") {
        reject(new Error(e.data.message));
      }
      worker.terminate();
      URL.revokeObjectURL(url);
    };
    worker.onerror = (e) => {
      reject(new Error(e.message));
      worker.terminate();
      URL.revokeObjectURL(url);
    };
  });
}
